// SPDX-License-Identifier: MIT
//
// ─────────────────────────────────────────────────────────────────────────────
// DEXignation — IDXRegistrar
//
// Derived from the ENS `BaseRegistrar` interface
//   Source : https://github.com/ensdomains/ens-contracts
//   File   : contracts/ethregistrar/BaseRegistrar.sol
//   © 2018-2024 Nick Johnson / ENS Labs, MIT License
//
// Modifications Copyright (c) 2026 DEXignation, licensed under MIT.
//
// 이 인터페이스는 ENS `BaseRegistrar` (MIT)에서 파생되었습니다.
// 변경 부분은 © 2026 DEXignation, MIT License 하에 배포됩니다.
//
// Notable changes / 주요 변경사항:
//   - `register()` takes the original `label` string so it can be stored
//     for on-chain SVG `tokenURI` rendering.
//     `register()`가 원본 `label` 문자열을 인자로 받아 온체인 SVG tokenURI
//     렌더링에 사용한다.
//   - Voluntary `burn()` allowed after `expiry + grace` so holders can
//     surrender stale domains and clear them from NFT marketplaces (ADR-012).
//     만료+유예 이후 보유자가 자발적으로 `burn()` 호출 가능, NFT 마켓
//     플레이스에서 stale 항목 정리 (ADR-012).
//   - Custom errors throughout.
//     전반에 걸친 커스텀 에러 사용.
// ─────────────────────────────────────────────────────────────────────────────

pragma solidity ^0.8.28;

import {IERC721} from "@openzeppelin/contracts/token/ERC721/IERC721.sol";

/// @title  IDXRegistrar
/// @notice Interface for DEXignation's ERC-721 backed name registrar.
///         ERC-721 기반 DEXignation 네임 Registrar 인터페이스.
interface IDXRegistrar is IERC721 {

  // ── Events ────────────────────────────────────────────────────────────────

  event ControllerAdded(address indexed controller);
  event ControllerRemoved(address indexed controller);
  event NameRegistered(uint256 indexed id, address indexed owner, uint256 expires);
  event NameRenewed(uint256 indexed id, uint256 expires);

  /// @dev Emitted when an expired token is burned, either by the
  ///      previous holder voluntarily or implicitly during re-registration.
  ///      만료 토큰이 소각될 때 (자발적 또는 재등록 중 묵시적).
  event NameBurned(uint256 indexed id, address indexed burner);

  // ── Errors ────────────────────────────────────────────────────────────────

  /// @dev This contract does not own the TLD node in the registry.
  ///      이 컨트랙트가 레지스트리의 TLD 소유자가 아님.
  error NotBaseNodeOwner();

  /// @dev Caller is not a whitelisted controller.
  ///      호출자가 화이트리스트된 컨트롤러가 아님.
  error UnauthorizedController();

  /// @dev Name is not available (still in expiry+grace window).
  ///      이름이 사용 불가 (만료+유예 기간 내).
  error NameNotAvailable(uint256 id);

  /// @dev Duration parameter is zero or causes overflow.
  ///      duration이 0이거나 오버플로우 유발.
  error InvalidDuration();

  /// @dev Token has no owner (already burned or never minted).
  ///      토큰 소유자가 없음 (소각되었거나 발행된 적 없음).
  error TokenOwnerNotFound();

  /// @dev Caller is not authorised for this token.
  ///      이 토큰에 대해 권한 없음.
  error Unauthorized();

  /// @dev Token is past its expiry timestamp.
  ///      토큰이 만료됨.
  error TokenExpired(uint256 tokenId);

  /// @dev Burn attempted before `expiry + GRACE_PERIOD`.
  ///      만료+유예 기간 이전에 burn 시도.
  error NotYetBurnable(uint256 tokenId, uint256 burnableAt);

  // ── Functions ─────────────────────────────────────────────────────────────

  function addController(address controller) external;
  function removeController(address controller) external;
  function setResolver(address resolver) external;
  function nameExpires(uint256 id) external view returns (uint256);
  function available(uint256 id) external view returns (bool);

  /// @notice Grace period (in seconds) after expiry during which the
  ///         previous owner may still renew.
  ///         만료 후에도 이전 소유자가 갱신할 수 있는 유예 기간(초).
  function gracePeriod() external view returns (uint256);

  function register(
    string calldata label,
    uint256 id,
    address owner,
    uint256 duration
  ) external returns (uint256);

  function renew(uint256 id, uint256 duration) external returns (uint256);

  function reclaim(uint256 id, address owner) external;

  /// @notice Burn an expired domain NFT after the grace period has passed.
  ///         만료된 도메인 NFT를 유예 기간 이후 소각.
  /// @dev    Permissionless: anyone can burn an expired token. This allows
  ///         NFT marketplaces and aggregators to clean up stale listings
  ///         without requiring action from the original holder.
  ///         The label string and expiry are deleted along with the token.
  ///         권한 불필요: 만료된 토큰은 누구나 burn 가능. NFT 마켓 등이
  ///         stale 항목을 보유자 행동 없이 정리 가능.
  ///         라벨 문자열과 expiry도 함께 삭제됨.
  /// @param  id tokenId (labelhash as uint256)
  function burn(uint256 id) external;
}

// SPDX-License-Identifier: MIT
//
// ─────────────────────────────────────────────────────────────────────────────
// DEXignation — IDXRegistrarController
//
// Derived from the ENS `IETHRegistrarController` interface, MIT License.
//   Source : https://github.com/ensdomains/ens-contracts
//   © 2018-2024 Nick Johnson / ENS Labs
//
// Modifications Copyright (c) 2026 DEXignation, MIT License.
//
// 이 인터페이스는 ENS `IETHRegistrarController` (MIT)에서 파생되었습니다.
// 변경 부분은 © 2026 DEXignation, MIT License 하에 배포됩니다.
//
// DEXignation additions / DEXignation 추가사항:
//   - Token-payment functions and events
//     토큰 결제 함수 및 이벤트
//   - `registerInventoryNames()` for owner pre-registration
//     오너 사전 등록을 위한 `registerInventoryNames()`
//   - Withdrawal entry points (`withdraw`, `withdrawToken`)
//     출금 함수 (`withdraw`, `withdrawToken`)
// ─────────────────────────────────────────────────────────────────────────────

pragma solidity ^0.8.28;

import {IDXRegistrar} from "./IDXRegistrar.sol";
import {IDXPriceOracle} from "../oracle/IDXPriceOracle.sol";

interface IDXRegistrarController {

  // ── Events ────────────────────────────────────────────────────────────────

  event NameRegistered(
    string label,
    bytes32 labelhash,
    address owner,
    uint256 price,
    uint256 expires
  );

  event NameRenewed(
    string label,
    bytes32 labelhash,
    uint256 price,
    uint256 expires
  );

  event NameRegisteredWithToken(
    string label,
    bytes32 labelhash,
    address owner,
    address paymentToken,
    uint256 tokenAmount,
    uint256 expires
  );

  event NameRenewedWithToken(
    string label,
    bytes32 labelhash,
    address paymentToken,
    uint256 tokenAmount,
    uint256 expires
  );

  // ── Errors ────────────────────────────────────────────────────────────────

  /// @dev Sent value is below the required rent price.
  ///      결제 금액이 가격보다 부족.
  error InsufficientFund(uint256 requiredPrice, uint256 sentPrice);

  /// @dev `recipient` is the zero address.
  ///      `recipient`가 zero address.
  error InvalidRecipient();

  /// @dev Name is not available.
  ///      이름 사용 불가.
  error NameNotAvailable(string name);

  /// @dev Payment token is not on the allow-list.
  ///      결제 토큰이 허용 목록에 없음.
  error TokenNotAllowed(address token);

  /// @dev Token has > 18 decimals (incompatible with attoUSD scale).
  ///      토큰 decimals가 18 초과 (attoUSD 스케일과 호환 불가).
  error UnsupportedTokenDecimals(uint8 decimals);

  /// @dev An unexpired commitment for the same hash already exists.
  ///      같은 해시의 만료되지 않은 commitment가 이미 존재.
  error UnexpiredCommitmentExists(bytes32 commitment);

  /// @dev `commit()` was never called for this commitment.
  ///      해당 commitment에 대한 `commit()` 호출이 없었음.
  error CommitmentNotFound(bytes32 commitment);

  /// @dev `commit()` was too recent (within `minCommitmentAge`).
  ///      `commit()`이 너무 최근 (minCommitmentAge 미경과).
  error CommitmentTooNew(bytes32 commitment);

  /// @dev `commit()` was too old (past `maxCommitmentAge`).
  ///      `commit()`이 너무 오래됨 (maxCommitmentAge 경과).
  error CommitmentTooOld(bytes32 commitment);

  /// @dev `maxCommitmentAge` <= `minCommitmentAge`.
  ///      maxCommitmentAge가 minCommitmentAge보다 작거나 같음.
  error MaxCommitmentAgeTooLow();

  /// @dev Low-level native transfer failed.
  ///      네이티브 전송 실패.
  error NativeTransferFailed(address to, uint256 amount);

  // ── Functions ─────────────────────────────────────────────────────────────

  function available(string calldata label) external view returns (bool);

  function rentPrice(uint256 duration) external view returns (uint256);

  /// @return Token amount required, in the token's minimum units (ceiling).
  ///         필요한 토큰 양 (토큰 최소 단위, 올림).
  function rentPriceInToken(
    uint256 duration,
    address token
  ) external view returns (uint256);

  function register(
    string calldata label,
    address owner,
    uint256 duration,
    address resolver,
    bytes32 secret
  ) external payable;

  function registerWithToken(
    string calldata label,
    address owner,
    uint256 duration,
    address resolver,
    address paymentToken,
    bytes32 secret
  ) external;

  function renew(string calldata label, uint256 duration) external payable;

  function renewWithToken(
    string calldata label,
    uint256 duration,
    address paymentToken
  ) external;

  function setAllowedPaymentToken(address token, bool allowed) external;

  function makeCommitment(
    string calldata name,
    address owner,
    bytes32 secret
  ) external pure returns (bytes32);

  function commit(bytes32 commitment) external;

  function setCommitmentAgeSettings(uint256 minAge, uint256 maxAge) external;

  function withdraw() external;

  function withdrawToken(address token) external;

  function registerInventoryNames(
    string[] calldata labels,
    address owner,
    uint256 duration,
    address resolver
  ) external;
}

